import { LINKBUTTON_SIZES } from "./linkbutton.constants";
const getIconSize = (size) => {
    switch (size) {
        case LINKBUTTON_SIZES[12]:
            return 0.75;
        case LINKBUTTON_SIZES[14]:
            return 0.875;
        default:
            return 1;
    }
};
export { getIconSize };
